import{_ as d,o as r,c as t,a3 as o}from"./chunks/framework.CRbjHCyB.js";const x=JSON.parse('{"title":"Index","description":"","frontmatter":{},"headers":[],"relativePath":"zh/clice/design/index.md","filePath":"zh/clice/design/index.md"}'),i={name:"zh/clice/design/index.md"};function a(l,e,n,c,s,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="index" tabindex="-1">Index <a class="header-anchor" href="#index" aria-label="Permalink to &quot;Index&quot;">​</a></h1><p>clice 维护一个持久化的符号索引，用于跨翻译单元的查询——查找引用、调用层次、工作区符号搜索等。索引在后台构建，使用 FlatBuffers 序列化存储到磁盘。</p><h2 id="架构" tabindex="-1">架构 <a class="header-anchor" href="#架构" aria-label="Permalink to &quot;架构&quot;">​</a></h2><h3 id="数据层" tabindex="-1">数据层 <a class="header-anchor" href="#数据层" aria-label="Permalink to &quot;数据层&quot;">​</a></h3><ul><li><p><strong>TUIndex</strong>（<code>src/index/tu_index.h</code>）— 单翻译单元的符号数据，由 <code>SemanticVisitor</code> 在编译时产生。包含符号哈希、出现位置和关系（定义、引用、基类、派生、调用者/被调用者）。这是一个临时输出，会被合并到下面的持久化存储中。</p></li><li><p><strong>ProjectIndex</strong>（<code>src/index/project_index.h</code>）— 全局跨 TU 符号索引。将符号哈希映射到其定义位置、名称、种类以及整个项目中聚合的关系。</p></li><li><p><strong>MergedIndex</strong>（<code>src/index/merged_index.h</code>）— 按文件分片，合并头文件上下文。单个头文件可能通过多个宿主源文件被索引；合并索引将这些协调为统一视图。</p></li></ul><h3 id="indexer-src-server-compiler-indexer-h" tabindex="-1">Indexer（<code>src/server/compiler/indexer.h</code>） <a class="header-anchor" href="#indexer-src-server-compiler-indexer-h" aria-label="Permalink to &quot;Indexer（`src/server/compiler/indexer.h`）&quot;">​</a></h3><p><code>Indexer</code> 类是查询和调度层。它本身不持有索引数据——持久化数据在 <code>Workspace</code> 中（ProjectIndex + MergedIndex 分片），未保存缓冲区的每文件数据在 <code>Session</code> 中（OpenFileIndex）。</p><p>职责：</p><ul><li>跨文件导航查询（定义、引用、层次）</li><li>符号搜索（<code>workspace/symbol</code>）</li><li>带空闲超时和去重的后台索引调度</li><li>将 TUIndex 结果合并到持久化存储</li><li>索引分片的磁盘保存/加载</li></ul><h2 id="后台索引" tabindex="-1">后台索引 <a class="header-anchor" href="#后台索引" aria-label="Permalink to &quot;后台索引&quot;">​</a></h2><p>文件编译后，其 TUIndex 会被合并到项目级索引中。后台索引在空闲期运行（可通过 <code>idle_timeout_ms</code> 配置，默认 3 秒）：</p><ol><li>文件在打开、保存或其依赖发生变化时入队。</li><li>空闲定时器去重快速变化——只有超时后才开始索引。</li><li>任务以可配置的并发度分发到无状态工作进程。</li><li>用户发起的请求（hover、补全）期间通过 <code>ScopedPause</code> 暂停索引。</li><li>通过 LSP <code>$/progress</code> 通知向客户端报告进度。</li></ol><h2 id="查询" tabindex="-1">查询 <a class="header-anchor" href="#查询" aria-label="Permalink to &quot;查询&quot;">​</a></h2><p>索引器支持以下跨 TU 查询：</p><table tabindex="0"><thead><tr><th>查询</th><th>方法</th></tr></thead><tbody><tr><td>跳转到定义</td><td><code>query_relations(path, pos, Definition)</code></td></tr><tr><td>查找引用</td><td><code>query_relations(path, pos, Reference)</code></td></tr><tr><td>调用层次（传入）</td><td><code>find_incoming_calls(hash)</code></td></tr><tr><td>调用层次（传出）</td><td><code>find_outgoing_calls(hash)</code></td></tr><tr><td>类型层次</td><td><code>resolve_hierarchy_item()</code></td></tr><tr><td>工作区符号</td><td>搜索 ProjectIndex</td></tr></tbody></table><p>对于有未保存更改的已打开文件，查询会先检查 Session 的 OpenFileIndex，然后回退到持久化的 MergedIndex。</p><h2 id="序列化" tabindex="-1">序列化 <a class="header-anchor" href="#序列化" aria-label="Permalink to &quot;序列化&quot;">​</a></h2><p>索引数据使用 <a href="https://flatbuffers.dev/" target="_blank" rel="noreferrer">FlatBuffers</a>（<code>src/index/schema.fbs</code>）序列化：</p><ul><li>零拷贝反序列化——索引分片可以直接从磁盘内存映射</li><li>紧凑的二进制格式——符号数据比 JSON/protobuf 更小</li><li>高效的部分读取——只加载查询所需的分片</li></ul><h2 id="符号标识" tabindex="-1">符号标识 <a class="header-anchor" href="#符号标识" aria-label="Permalink to &quot;符号标识&quot;">​</a></h2><p>符号通过 64 位哈希（<code>SymbolHash</code>）标识，派生自 Clang 的 USR（Unified Symbol Resolution）字符串。USR 生成（<code>src/index/usr_generation.cpp</code>）为每个符号产生一个跨 TU 稳定的规范标识符。</p>',21)])])}const u=d(i,[["render",a]]);export{x as __pageData,u as default};
